#include <stdio.h>
#include <stdlib.h>

const long long mod = 1e9 + 7; // Constant for modulo operation
const long long inf = 1e18;    // A large number representing infinity

int main() {
    int n; // Number of fees
    scanf("%d", &n); // Read the number of fees

    int* fees = (int*)malloc(n * sizeof(int)); // Dynamically allocate memory for fees
    for (int i = 0; i < n; i++)
        scanf("%d", &fees[i]); // Read each fee

    // Special cases for 1 or 2 fees
    if (n == 1) {
        printf("%d\n", fees[0]); // Only one fee, output it
        free(fees); // Free allocated memory
        return 0;
    }

    if (n == 2) {
        printf("%d\n", fees[0] + fees[1]); // Sum of two fees
        free(fees); // Free allocated memory
        return 0;
    }

    // Create a 2D array for dynamic programming
    int** dp = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        dp[i] = (int*)malloc(3 * sizeof(int));
    }

    // Initialize the base cases for dp
    dp[0][1] = dp[0][2] = fees[0]; 
    dp[1][0] = fees[0];
    dp[1][1] = fees[1];
    dp[1][2] = fees[0] + fees[1];

    // Fill the dp table
    for (int i = 2; i < n; i++) {
        // Max sum if we don't choose fees[i]
        dp[i][0] = dp[i - 1][0] > dp[i - 1][1] ? (dp[i - 1][0] > dp[i - 1][2] ? dp[i - 1][0] : dp[i - 1][2]) : (dp[i - 1][1] > dp[i - 1][2] ? dp[i - 1][1] : dp[i - 1][2]);

        // Max sum if we choose fees[i] but not fees[i - 1]
        dp[i][1] = fees[i] + dp[i - 1][0];

        // Max sum if we choose fees[i] and fees[i - 1] but not fees[i - 2]
        dp[i][2] = fees[i] + fees[i - 1] + dp[i - 2][0];
    }

    // Output the maximum sum possible
    int maxSum = dp[n - 1][0];
    for (int j = 1; j < 3; j++) {
        if (dp[n - 1][j] > maxSum) {
            maxSum = dp[n - 1][j];
        }
    }
    printf("%d\n", maxSum); // Print the result

    // Free allocated memory
    for (int i = 0; i < n; i++) {
        free(dp[i]); // Free each sub-array
    }
    free(dp); // Free the main array
    free(fees); // Free allocated memory for fees

    return 0;
}

