import java.util.*;
import java.lang.*;
import java.io.*;

class Main
{
    // Constant for modulo operation
    static final long MOD = 1000000007; 
    // A large number representing infinity
    static final long INF = 1000000000000000000L; 

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        // Read the number of fees
        int n = scanner.nextInt(); 

        // Create an array to store fees
        int[] fees = new int[n]; 
        for (int i = 0; i < n; i++) {
            fees[i] = scanner.nextInt(); // Read each fee
        }

        // Special cases for 1 or 2 fees
        if (n == 1) {
            System.out.println(fees[0]); // Only one fee, output it
            return;
        }

        if (n == 2) {
            System.out.println(fees[0] + fees[1]); // Sum of two fees
            return;
        }

        // Create a 2D array for dynamic programming
        int[][] dp = new int[n][3];

        // Initialize the base cases for dp
        dp[0][1] = dp[0][2] = fees[0]; 
        dp[1][0] = fees[0];
        dp[1][1] = fees[1];
        dp[1][2] = fees[0] + fees[1];

        // Fill the dp table
        for (int i = 2; i < n; i++) {
            // Max sum if we don't choose fees[i]
            dp[i][0] = Math.max(Math.max(dp[i - 1][0], dp[i - 1][1]), dp[i - 1][2]);
            // Max sum if we choose fees[i] but not fees[i - 1]
            dp[i][1] = fees[i] + dp[i - 1][0];
            // Max sum if we choose fees[i] and fees[i - 1] but not fees[i - 2]
            dp[i][2] = fees[i] + fees[i - 1] + dp[i - 2][0];
        }

        // Output the maximum sum possible
        System.out.println(Math.max(Math.max(dp[n - 1][0], dp[n - 1][1]), dp[n - 1][2]));

        scanner.close();
    }
}

